   117	bool should_drop_transport_block(int slot, uint16_t rnti)
   118	{
   119	  if (!is_channel_modeling())
   120	  {
   121	    return false;
   122	  }
   123	
   124	  /* We want to avoid dropping setup messages because this would be pathological. */
   125	  NR_UE_MAC_INST_t *mac = get_mac_inst(0);
   126	  if (mac->ra.ra_state < nrRA_SUCCEEDED) {
   127	    LOG_D(NR_MAC, "Not dropping because MAC state: %d", mac->ra.ra_state);
   128	    return false;
   129	  }
   130	
   131	  /* Get block error rate (bler_val) from table based on every saved
   132	     MCS and SINR to be used as the cutoff rate for dropping packets.
   133	     Generate random uniform vairable to compare against bler_val. */
   134	  int num_pdus = slot_rnti_mcs[slot].num_pdus;
   135	  assert(slot < 20 && slot >= 0);
   136	  LOG_D(NR_MAC, "rnti: %x  num_pdus %d state %d slot %u sinr %f\n",
   137	        rnti, num_pdus, mac->ra.ra_state, slot, slot_rnti_mcs[slot].sinr);
   138	  assert(num_pdus > 0);
   139	  CHECK_INDEX(slot_rnti_mcs[slot].rnti, num_pdus);
   140	  CHECK_INDEX(slot_rnti_mcs[slot].mcs, num_pdus);
   141	  CHECK_INDEX(slot_rnti_mcs[slot].drop_flag, num_pdus);
   142	  int n = 0;
   143	  uint8_t mcs = 99;
   144	  for (n = 0; n < num_pdus; n++)
   145	  {
   146	    if (slot_rnti_mcs[slot].rnti[n] == rnti)
   147	    {
   148	      mcs = slot_rnti_mcs[slot].mcs[n];
   149	    }
   150	    if (mcs != 99)
   151	    {
   152	      /* Use MCS to get the bler value. Since there can be multiple MCS
   153	         values for a particular slot, we verify that all PDUs are not
   154	         flagged for drop before returning. If even one is flagged for drop
   155	         we return immediately because we drop the entire packet. */
   156	
   157	      LOG_D(NR_MAC, "rnti: %x mcs %u slot %u sinr %f\n",
   158	        slot_rnti_mcs[slot].rnti[n], mcs, slot, slot_rnti_mcs[slot].sinr);
   159	
   160	      float bler_val;
   161	      if (slot_rnti_mcs[slot].rvIndex[n] != 0)
   162	        bler_val = 0;
   163	      else
   164	        bler_val = get_bler_val(mcs, ((int)(slot_rnti_mcs[slot].sinr * 10)));
   165	      double drop_cutoff = ((double) rand() / (RAND_MAX));
   166	      assert(drop_cutoff <= 1);
   167	      LOG_D(NR_MAC, "SINR = %f, Bler_val = %f, MCS = %"PRIu8"\n", slot_rnti_mcs[slot].sinr, bler_val, slot_rnti_mcs[slot].mcs[n]);
   168	      if (drop_cutoff <= bler_val)
   169	      {
   170	        slot_rnti_mcs[slot].drop_flag[n] = true;
   171	        LOG_T(NR_MAC, "We are dropping this packet. Bler_val = %f, MCS = %"PRIu8", slot = %d\n", bler_val, slot_rnti_mcs[slot].mcs[n], slot);
   172	        return slot_rnti_mcs[slot].drop_flag[n];
   173	      }
   174	    }
   175	
   176	  }
   177	
   178	  if (mcs == 99)
   179	  {
   180	    LOG_E(NR_MAC, "NO MCS Found for rnti %x. slot_rnti_mcs[%d].mcs[%d] \n", rnti, slot, n);
   181	    abort();
   182	  }
   183	  return false;
   184	}
